from decimal import Decimal
from typing import List
from src.pdf_generator import InvoicePDFGenerator


class Invoice:
    def __init__(self, customer: str, items: List[dict]):
        self.customer = customer
        self.items = items

    def calculate_total(self) -> Decimal:
        total = Decimal('0')
        for item in self.items:
            total += Decimal(str(item['price'])) * item['quantity']
        return total

    def calculate_tax(self, rate: Decimal = Decimal('0.1')) -> Decimal:
        return self.calculate_total() * rate

    def generate_pdf(self, output_path: str) -> str:
        generator = InvoicePDFGenerator()
        return generator.generate(self, output_path)

    def send_email(self, to: str, smtp_host: str):
        pdf_path = self.generate_pdf(f'/tmp/invoice_{self.customer}.pdf')
